import 'dart:mirrors';

class Info {
  final String message;
  const Info(this.message);
}

@Info('Important class')
class MyClass {}

void main() {
  var mirror = reflectClass(MyClass);
  var metadata = mirror.metadata;
  for (var m in metadata) {
    if (m.reflectee is Info) {
      print((m.reflectee as Info).message);
    }
  }
}

